// // This module selects between two 4-bit input data lines (d0 and d1) based on the select signal (s). When s is high (1), the output (y) reflects the value of d0; when s is low (0), the output takes the value from d1.
module top_module(d0,d1,y,s);input [3:0]  d0,d1;
    input        s;
    output [3:0] y;
    reg    [3:0] y;

    always@(d0 or d1 or s)
    begin 
        if (s == 1)
            y = d1;
        else 
            y = d0;
    end
endmodule
